patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 21c937530cd8..df5241d0d1b4 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4731,6 +4731,19 @@ static Value *simplifySelectWithICmpCond(Value *CondVal, Value *TrueVal,
   // the arms of the select. See if substituting this value into the arm and
   // simplifying the result yields the same value as the other arm.
   if (Pred == ICmpInst::ICMP_EQ) {
+    // Don't perform equivalence substitution for the specific pattern
+    // select (icmp eq ptr %a, %b), %a, %b when both %a and %b are non-constant
+    // and don't have the same underlying object, as it may not be safe
+    // due to potential differences in provenance.
+    if (CmpLHS->getType()->isPointerTy() &&
+        !isa<Constant>(CmpLHS) && !isa<Constant>(CmpRHS) &&
+        ((TrueVal == CmpLHS && FalseVal == CmpRHS) ||
+         (TrueVal == CmpRHS && FalseVal == CmpLHS))) {
+      Value *UnderlyingLHS = getUnderlyingObject(CmpLHS);
+      Value *UnderlyingRHS = getUnderlyingObject(CmpRHS);
+      if (UnderlyingLHS != UnderlyingRHS)
+        return nullptr;
+    }
     if (Value *V = simplifySelectWithEquivalence({{CmpLHS, CmpRHS}}, TrueVal,
                                                  FalseVal, Q, MaxRecurse))
       return V;

